    greeting: "Hello! I am Prof. Arjun Verma, your Physics guide for JEE Mains and Advanced. Physics is about understanding logic, not just memorizing formulas. You can also send me a photo of any question or diagram! Which topic or problem shall we start with today?",
    svg: `<svg viewBox="0 0 140 210" xmlns="http://www.w3.org/2000/svg" style="width:128px;height:198px"><rect x="32" y="115" width="76" height="88" rx="12" fill="#1a2a4a"/><polygon points="62,115 78,115 74,135 70,138 66,135" fill="#e8f0ff"/><polygon points="70,118 73,118 72,148 70,152 68,148 67,118" fill="#388bfd"/><rect x="62" y="104" width="16" height="14" rx="4" fill="#d4a574"/><ellipse cx="70" cy="76" rx="28" ry="30" fill="#d4a574"/><path d="M42 72 Q44 48 70 44 Q96 48 98 72 Q94 54 70 52 Q48 54 44 68 Z" fill="#1a1200"/><path d="M52 54 Q58 60 62 70" stroke="#2a1e00" stroke-width="1.5" fill="none"/><path d="M51 70 Q58 66 65 69" stroke="#1a1200" stroke-width="2" fill="none"/><path d="M75 69 Q82 66 89 70" stroke="#1a1200" stroke-width="2" fill="none"/><ellipse cx="58" cy="76" rx="4" ry="4.5" fill="#1a0a00"/><ellipse cx="82" cy="76" rx="4" ry="4.5" fill="#1a0a00"/><circle cx="60" cy="74" r="1.2" fill="white"/><circle cx="84" cy="74" r="1.2" fill="white"/><path d="M67 86 Q70 91 73 86" stroke="#b08060" stroke-width="1.5" fill="none"/><path d="M62 94 Q66 97 70 95 Q74 97 78 94" stroke="#1a1200" stroke-width="2" fill="#1a1200"/><path id="mouth" d="M64 99 Q70 103 76 99" stroke="#905040" stroke-width="2" fill="none" stroke-linecap="round"/><ellipse cx="42" cy="78" rx="5" ry="7" fill="#d4a574"/><ellipse cx="98" cy="78" rx="5" ry="7" fill="#d4a574"/><path d="M108 128 Q122 142 118 165" stroke="#1a2a4a" stroke-width="12" fill="none" stroke-linecap="round"/><line x1="118" y1="162" x2="128" y2="180" stroke="#e8f0ff" stroke-width="3" stroke-linecap="round"/><circle cx="55" cy="148" r="6" fill="none" stroke="#388bfd" stroke-width="1.2"/><ellipse cx="55" cy="148" rx="10" ry="4" fill="none" stroke="#388bfd" stroke-width="1" transform="rotate(30 55 148)"/><circle cx="55" cy="148" r="1.5" fill="#388bfd"/></svg>`,
  },
  meera: {
    id: "meera", name: "Ms. Meera", fullName: "Ms. Meera Nair",
    role: "Chemistry Expert · NEET & JEE", exam: "NEET & JEE",
    color: "#f85149", colorRGB: "248,81,73",
    examBg: "rgba(248,81,73,0.1)", examBorder: "rgba(248,81,73,0.3)",
    icon: "🧪", subjects: ["Organic Chem", "Inorganic Chem", "Physical Chem"],
    pitch: 1.1, rate: 0.79,
    quickTopics: [
      "How to master Organic Chemistry reactions?",
      "Periodic table trends explained simply",
      "Mole concept step by step",
      "Most important Chemistry topics for NEET?",
    ],
    system: `You are Ms. Meera Nair, an expert Chemistry teacher for NEET UG and JEE Mains in India. You teach Organic, Inorganic, and Physical Chemistry from NCERT Class 11 and 12. Make difficult reactions easy with story-like explanations and memory tricks. Highlight reactions frequently asked in NEET and JEE. Reference NCERT and P. Bahadur when helpful. Be enthusiastic, warm, and patient. Speak in simple clear Indian English. If the student sends a photo of a reaction, equation, or question, read it carefully and explain or solve it in detail. STRICT RULES: Never use markdown, asterisks, bullet points, dashes, headers, or diagrams. Never use symbols like *, **, #, -, or |. Write only in plain flowing sentences and short paragraphs like a teacher speaking to a student.`,
    greeting: "Hello students! I am Ms. Meera Nair, your Chemistry teacher for NEET and JEE. From organic mechanisms to electrochemistry, I will explain everything step by step. You can also send me a photo of any question or reaction! What chemistry doubt shall we clear today?",
    svg: `<svg viewBox="0 0 140 210" xmlns="http://www.w3.org/2000/svg" style="width:128px;height:198px"><rect x="28" y="114" width="84" height="90" rx="12" fill="#eef4fb"/><rect x="28" y="114" width="84" height="90" rx="12" fill="none" stroke="#c8d8e8" stroke-width="1.5"/><polygon points="60,114 80,114 75,130 70,133 65,130" fill="#ff6b6b"/><rect x="38" y="148" width="20" height="18" rx="4" fill="none" stroke="#c8d8e8" stroke-width="1.5"/><line x1="43" y1="148" x2="43" y2="142" stroke="#388bfd" stroke-width="2" stroke-linecap="round"/><line x1="48" y1="148" x2="48" y2="142" stroke="#f85149" stroke-width="2" stroke-linecap="round"/><rect x="62" y="103" width="16" height="14" rx="4" fill="#e0a882"/><ellipse cx="70" cy="75" rx="27" ry="30" fill="#e0a882"/><path d="M43 70 Q44 44 70 41 Q96 44 97 70 L97 80 Q90 70 70 68 Q50 70 43 80 Z" fill="#0d0500"/><path d="M43 70 Q36 90 38 115" stroke="#0d0500" stroke-width="10" fill="none" stroke-linecap="round"/><path d="M97 70 Q104 90 102 115" stroke="#0d0500" stroke-width="10" fill="none" stroke-linecap="round"/><circle cx="70" cy="64" r="2.5" fill="#f85149"/><path d="M52 69 Q58 65 64 68" stroke="#0d0500" stroke-width="1.8" fill="none"/><path d="M76 68 Q82 65 88 69" stroke="#0d0500" stroke-width="1.8" fill="none"/><ellipse cx="58" cy="75" rx="4.5" ry="5" fill="#0d0500"/><ellipse cx="82" cy="75" rx="4.5" ry="5" fill="#0d0500"/><circle cx="60" cy="73" r="1.3" fill="white"/><circle cx="84" cy="73" r="1.3" fill="white"/><path d="M67 86 Q70 90 73 86" stroke="#c08060" stroke-width="1.3" fill="none"/><circle cx="67" cy="87" r="1.5" fill="none" stroke="#f7a325" stroke-width="1.2"/><path id="mouth" d="M64 95 Q70 100 76 95" stroke="#c06050" stroke-width="2" fill="none" stroke-linecap="round"/><ellipse cx="43" cy="78" rx="5" ry="7" fill="#e0a882"/><ellipse cx="97" cy="78" rx="5" ry="7" fill="#e0a882"/><circle cx="43" cy="85" r="3.5" fill="#f85149" stroke="#c04030" stroke-width="1"/><circle cx="97" cy="85" r="3.5" fill="#f85149" stroke="#c04030" stroke-width="1"/><path d="M100 130 Q114 148 108 168" stroke="#eef4fb" stroke-width="11" fill="none" stroke-linecap="round"/><path d="M100 162 Q98 172 106 178 Q116 178 114 168 Z" fill="#f85149" opacity="0.7"/><rect x="102" y="155" width="8" height="6" rx="2" fill="none" stroke="#f85149" stroke-width="1.5"/></svg>`,
  },
  ravi: {
    id: "ravi", name: "Mr. Ravi", fullName: "Mr. Ravi Kumar",
    role: "Mathematics Expert · JEE", exam: "JEE Mains & Adv",
    color: "#a371f7", colorRGB: "163,113,247",
    examBg: "rgba(163,113,247,0.1)", examBorder: "rgba(163,113,247,0.3)",
    icon: "📐", subjects: ["Calculus", "Algebra", "Coordinate Geometry"],
    pitch: 0.9, rate: 0.77,
    quickTopics: [
      "How to solve integration problems fast?",
      "Tricks for JEE coordinate geometry",
      "How to approach Permutations & Combinations?",
      "Most important Maths topics for JEE Mains?",
    ],
    system: `You are Mr. Ravi Kumar, a top Mathematics teacher for JEE Mains and JEE Advanced in India. You teach Calculus, Algebra, Coordinate Geometry, Trigonometry, and Probability. Explain each concept step by step with clarity. Give shortcuts and tricks for solving JEE problems faster. Be confident, systematic, and very clear. Speak in simple clear Indian English. If the student sends a photo of a maths problem or equation, read it carefully and solve it step by step with full working. STRICT RULES: Never use markdown, asterisks, bullet points, dashes, headers, or diagrams. Never use symbols like *, **, #, -, or |. Write only in plain flowing sentences and short paragraphs like a teacher speaking to a student.`,
    greeting: "Hello! I am Mr. Ravi Kumar, your Mathematics teacher for JEE. Many students fear Maths, but with the right approach it becomes your strongest subject. You can also send me a photo of any problem! Which topic shall we work on today?",
    svg: `<svg viewBox="0 0 140 210" xmlns="http://www.w3.org/2000/svg" style="width:128px;height:198px"><rect x="30" y="114" width="80" height="90" rx="12" fill="#2a1a4a"/><line x1="70" y1="114" x2="70" y2="200" stroke="#a371f7" stroke-width="1.5" opacity="0.45"/><circle cx="70" cy="122" r="2" fill="#a371f7" opacity="0.55"/><circle cx="70" cy="132" r="2" fill="#a371f7" opacity="0.55"/><circle cx="70" cy="142" r="2" fill="#a371f7" opacity="0.55"/><rect x="62" y="104" width="16" height="14" rx="4" fill="#b07840"/><ellipse cx="70" cy="76" rx="27" ry="30" fill="#b07840"/><path d="M44 72 Q46 48 70 44 Q94 48 96 72 Q92 56 70 54 Q52 56 46 68 Z" fill="#0a0800"/><path d="M50 68 Q58 64 65 67" stroke="#0a0800" stroke-width="2.5" fill="none"/><path d="M75 67 Q82 64 90 68" stroke="#0a0800" stroke-width="2.5" fill="none"/><rect x="49" y="72" width="18" height="12" rx="5" fill="none" stroke="#a371f7" stroke-width="2"/><rect x="73" y="72" width="18" height="12" rx="5" fill="none" stroke="#a371f7" stroke-width="2"/><line x1="67" y1="78" x2="73" y2="78" stroke="#a371f7" stroke-width="2"/><ellipse cx="58" cy="78" rx="4" ry="4" fill="#1a1200"/><ellipse cx="82" cy="78" rx="4" ry="4" fill="#1a1200"/><circle cx="60" cy="76" r="1.2" fill="white"/><circle cx="84" cy="76" r="1.2" fill="white"/><path d="M67 88 Q70 93 73 88" stroke="#906040" stroke-width="1.5" fill="none"/><path d="M48 92 Q52 106 70 110 Q88 106 92 92" fill="#1a1000" opacity="0.4"/><path id="mouth" d="M63 96 Q70 100 77 96" stroke="#804030" stroke-width="2" fill="none" stroke-linecap="round"/><ellipse cx="43" cy="78" rx="5" ry="7" fill="#b07840"/><ellipse cx="97" cy="78" rx="5" ry="7" fill="#b07840"/><path d="M110 126 Q126 142 120 164" stroke="#2a1a4a" stroke-width="12" fill="none" stroke-linecap="round"/><rect x="118" y="158" width="6" height="20" rx="3" fill="white" transform="rotate(20 118 158)"/><text x="36" y="162" fontFamily="serif" fontSize="9" fill="#a371f7" opacity="0.65">∫dx</text><text x="36" y="174" fontFamily="serif" fontSize="8" fill="#a371f7" opacity="0.45">Σ∞</text></svg>`,
