// ── Helper: convert File to base64 ────────────────────────────────────────
function fileToBase64(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result.split(",")[1]); // strip data:...;base64,
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

// ── Component ──────────────────────────────────────────────────────────────
export default function VIDYAPage({ userName, hideVidyaFab = false }) {
  const [current, setCurrent] = useState(TEACHERS.priya);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [busy, setBusy] = useState(false);
  const [autoVoice, setAutoVoice] = useState(false);
  const [chatHistory, setChatHistory] = useState([]);
  const [apiKeyInput, setApiKeyInput] = useState("");
  const [apiKey, setApiKey] = useState(localStorage.getItem("vidya_openrouter_key") || "");
  const [showKeyPrompt, setShowKeyPrompt] = useState(false);

  // ── Image upload state ──
  const [uploadedImage, setUploadedImage] = useState(null);   // { base64, mimeType, previewUrl }
  const fileInputRef = useRef(null);

  const chatboxRef = useRef(null);
  const mouthIntervalRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => {
    if (chatboxRef.current)
      chatboxRef.current.scrollTop = chatboxRef.current.scrollHeight;
  }, [messages]);

  useEffect(() => { selectTeacher("priya"); }, []); // eslint-disable-line

  useEffect(() => {
    if (!apiKey) setShowKeyPrompt(true);
    else setShowKeyPrompt(false);
  }, [apiKey]);

  function saveApiKey() {
    const k = apiKeyInput.trim();
    if (!k) return;
    localStorage.setItem("vidya_openrouter_key", k);
    setApiKey(k);
    setApiKeyInput("");
  }

  function selectTeacher(id) {
    const t = TEACHERS[id];
    setCurrent(t);
    setChatHistory([]);
    setMessages([{ role: "greeting", text: t.greeting, id: Date.now() }]);
    stopMouth();
    if (window.speechSynthesis) window.speechSynthesis.cancel();
  }

  // ── Image upload handler ──────────────────────────────────────────────
  async function handleImageSelect(e) {
    const file = e.target.files?.[0];
    if (!file) return;

    // Only allow images
    if (!file.type.startsWith("image/")) {
      alert("Please select an image file (JPG, PNG, WEBP, etc.)");
      return;
    }

    // Max 5MB
    if (file.size > 5 * 1024 * 1024) {
      alert("Image is too large. Please use an image under 5MB.");
      return;
    }

    try {
      const base64 = await fileToBase64(file);
      const previewUrl = URL.createObjectURL(file);
      setUploadedImage({ base64, mimeType: file.type, previewUrl, name: file.name });
    } catch {
      alert("Could not read image. Please try again.");
    }

    // Reset file input so same file can be re-selected
    e.target.value = "";
  }

  function removeImage() {
    if (uploadedImage?.previewUrl) URL.revokeObjectURL(uploadedImage.previewUrl);
    setUploadedImage(null);
  }

  // ── Voice ──────────────────────────────────────────────────────────────
  function getBestVoice(t) {
    const voices = window.speechSynthesis?.getVoices() || [];
    const male = t.id === "arjun" || t.id === "ravi";
    const en = voices.filter(v => /en/i.test(v.lang));
    if (male) return en.find(v => /male/i.test(v.name)) || en[0] || voices[0];
    return en.find(v => /female/i.test(v.name)) || en[0] || voices[0];
  }

  function speak(text, t) {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const clean = text.replace(/[*_#`]/g, "").replace(/\n+/g, ". ");
    const u = new SpeechSynthesisUtterance(clean);
    u.pitch = t.pitch; u.rate = t.rate; u.volume = 1;
    const v = getBestVoice(t); if (v) u.voice = v;
    u.onstart = startMouth;
    u.onend = stopMouth;
    u.onerror = stopMouth;
    window.speechSynthesis.speak(u);
  }

  function startMouth() {
    const ring = document.getElementById("vidya-pulse-ring");
    if (ring) ring.classList.add("pulsing");
    clearInterval(mouthIntervalRef.current);
    mouthIntervalRef.current = setInterval(() => {
      const m = document.getElementById("mouth");
      if (!m) return;
      const y = 97 + Math.random() * 9;
      m.setAttribute("d", `M64 96 Q70 ${y} 76 96`);
    }, 120);
  }

  function stopMouth() {
    clearInterval(mouthIntervalRef.current);
    const ring = document.getElementById("vidya-pulse-ring");
    if (ring) ring.classList.remove("pulsing");
    const m = document.getElementById("mouth");
    if (m) m.setAttribute("d", "M64 96 Q70 100 76 96");
  }

  // ── Send via OpenRouter ───────────────────────────────────────────────
  async function sendMessage(overrideText) {
    if (busy) return;
    const text = (overrideText || input).trim();
    const hasImage = !!uploadedImage;

    if (!text && !hasImage) return;
    if (!apiKey) { setShowKeyPrompt(true); return; }

    setInput("");

    // Build user message for UI
    const userMsg = {
      role: "user",
      text: text || "📷 (image sent)",
      imagePreview: hasImage ? uploadedImage.previewUrl : null,
      id: Date.now(),
    };
    setMessages(prev => [...prev, userMsg]);

    // Snapshot and clear image
    const imageData = uploadedImage;
    setUploadedImage(null);

    setBusy(true);

    try {
      // Build content for API: image + text or just text
      let userContent;
      if (hasImage) {
        userContent = [
          {
            type: "image_url",
            image_url: {
              url: `data:${imageData.mimeType};base64,${imageData.base64}`,
            },
          },
          {
            type: "text",
            text: text || "Please explain or solve whatever is shown in this image.",
          },
        ];
      } else {
        userContent = text;
      }

      // Use vision model if image, else fast text model
      const model = hasImage ? OPENROUTER_MODEL_VISION : OPENROUTER_MODEL_TEXT;

      const messagesPayload = [
        { role: "system", content: current.system },
        ...chatHistory,
        { role: "user", content: userContent },
      ];

      const res = await fetch("https://openrouter.ai/api/v1/chat/completions", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${apiKey}`,
          "HTTP-Referer": window.location.origin,
          "X-Title": "VIDYA AI Tutor",
        },
        body: JSON.stringify({
          model,
          messages: messagesPayload,
          max_tokens: 1024,
          temperature: 0.7,
        }),
      });

      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        const msg = err?.error?.message || `API error ${res.status}`;
        if (res.status === 401 || res.status === 403) {
          setShowKeyPrompt(true);
          setApiKey("");
          localStorage.removeItem("vidya_openrouter_key");
        }
        throw new Error(msg);
      }

      const data = await res.json();
      const rawReply =
        data?.choices?.[0]?.message?.content ||
        "Sorry, I could not process that. Please try again.";

      // Strip any markdown the model still produces
      const reply = rawReply
        .replace(/#{1,6}\s*/g, "")
        .replace(/\*\*(.*?)\*\*/g, "$1")
        .replace(/\*(.*?)\*/g, "$1")
        .replace(/`{1,3}[^`]*`{1,3}/g, "")
        .replace(/^\s*[-•]\s+/gm, "")
        .replace(/^\s*\d+\.\s+/gm, "")
        .replace(/\|.*\|/g, "")
        .replace(/\n{3,}/g, "\n\n")
        .trim();

      // For chat history, store text-only version of user turn
      const newHistory = [
        ...chatHistory,
        { role: "user", content: text || "(image question)" },
        { role: "assistant", content: reply },
      ];
      setChatHistory(newHistory.slice(-20));
      setMessages(prev => [...prev, { role: "bot", text: reply, id: Date.now() }]);
      if (autoVoice) speak(reply, current);

    } catch (e) {
      setMessages(prev => [...prev, {
        role: "bot",
        text: `⚠️ ${e.message || "Connection issue. Please check your internet and try again."}`,
        id: Date.now()
      }]);
    }

    setBusy(false);
    inputRef.current?.focus();
  }

  const accentStyle = {
    "--vidya-accent": current.color,
    "--vidya-accent-rgb": current.colorRGB,
  };

  return (
    <PageLayout userName={userName} hideVidyaFab={hideVidyaFab}>
      <div className="vidya-root" style={accentStyle}>

        {/* ── API Key Setup Prompt ── */}
        {showKeyPrompt && (
          <div className="vidya-key-overlay">
            <div className="vidya-key-modal">
              <div className="vidya-key-icon">🔑</div>
              <h2>Enter your OpenRouter API Key</h2>
              <p>
                VIDYA AI uses OpenRouter (100% free). Get your free key from{" "}
                <a href="https://openrouter.ai/keys" target="_blank" rel="noreferrer">
                  openrouter.ai/keys
                </a>{" "}
                — sign up with Google, no billing needed.
              </p>
              <input
                className="vidya-key-input"
                type="password"
                placeholder="Paste your OpenRouter API key here…"
                value={apiKeyInput}
                onChange={e => setApiKeyInput(e.target.value)}
                onKeyDown={e => { if (e.key === "Enter") saveApiKey(); }}
                autoFocus
              />
              <button className="vidya-key-btn" onClick={saveApiKey}
                style={{ background: `linear-gradient(135deg,${current.color},${current.color}bb)` }}>
                Save & Start Chatting →
              </button>
              <p className="vidya-key-note">Your key is saved locally in your browser only.</p>
            </div>
          </div>
        )}

        {/* ── Sidebar ── */}
        <aside className="vidya-sidebar">
          <div className="vidya-sidebar-top">

            {/* Brand */}
            <div className="vidya-brand">
              <div className="vidya-brand-icon" style={{ background: `linear-gradient(135deg,${current.color},${current.color}aa)` }}>🎓</div>
              <div>
                <div className="vidya-brand-text">VidyaBot</div>
                <div className="vidya-brand-sub">AI Exam Tutor · OpenRouter</div>
              </div>
            </div>

            {/* Exam badges */}
            <div className="vidya-exam-row">
              <span className="vidya-badge badge-neet">NEET</span>
              <span className="vidya-badge badge-jeem">JEE Mains</span>
              <span className="vidya-badge badge-jeea">JEE Adv</span>
              <span className="vidya-badge badge-board">Boards</span>
            </div>

            {/* Avatar stage */}
            <div className="vidya-avatar-stage">
              <div className="vidya-stage-bg"
                style={{ background: `radial-gradient(ellipse at 50% 110%, rgba(${current.colorRGB},0.17) 0%, transparent 65%)` }} />
              <div className="vidya-stage-glow" style={{ background: `rgba(${current.colorRGB},0.25)` }} />
              <div className="vidya-pulse-ring" id="vidya-pulse-ring" style={{ borderColor: current.color }} />
              <div className="vidya-avatar-wrap"
                dangerouslySetInnerHTML={{ __html: current.svg }} />
            </div>

            {/* Teacher info */}
            <div className="vidya-teacher-info">
              <h2>{current.name}</h2>
              <span className="vidya-role-tag"
                style={{ background: current.examBg, color: current.color }}>{current.role}</span>
              <div className="vidya-subject-chips">
                {current.subjects.map(s => <span key={s} className="vidya-chip">{s}</span>)}
              </div>
            </div>
          </div>

          <div className="vidya-divider" />
          <div className="vidya-section-label">CHOOSE YOUR TEACHER</div>

          {/* Teacher grid */}
          <div className="vidya-teacher-grid">
            {Object.values(TEACHERS).map(t => (
              <div key={t.id}
                className={`vidya-t-card ${current.id === t.id ? "active" : ""}`}
                style={current.id === t.id ? { borderColor: t.color, background: `rgba(${t.colorRGB},0.07)` } : {}}
                onClick={() => selectTeacher(t.id)}>
                <div className="vidya-t-icon">{t.icon}</div>
                <div className="vidya-t-name">{t.name}</div>
                <div className="vidya-t-sub">{t.subjects[0]}</div>
              </div>
            ))}
          </div>

          <div className="vidya-divider" />

          {/* Quick questions */}
          <div className="vidya-qt-wrap">
            <div className="vidya-qt-label">Quick Questions</div>
            {current.quickTopics.map(q => (
              <button key={q} className="vidya-qt-btn" onClick={() => sendMessage(q)}>
                💬 {q}
              </button>
            ))}
          </div>

          {/* Voice toggle */}
          <div className="vidya-voice-wrap">
            <button
              className={`vidya-voice-btn ${autoVoice ? "on" : ""}`}
              style={autoVoice ? { borderColor: current.color, color: current.color } : {}}
              onClick={() => setAutoVoice(v => !v)}>
              {autoVoice ? "🔊  Auto-Speak: ON" : "🔇  Auto-Speak: OFF"}
            </button>
          </div>

          {/* Change API Key */}
          {apiKey && (
            <div className="vidya-voice-wrap">
              <button className="vidya-voice-btn"
                onClick={() => { setShowKeyPrompt(true); setApiKey(""); localStorage.removeItem("vidya_openrouter_key"); }}>
                🔑 Change API Key
              </button>
            </div>
          )}
        </aside>

        {/* ── Chat main ── */}
        <main className="vidya-chat-main">

          {/* Header */}
          <div className="vidya-chat-header">
            <div>
              <div className="vidya-chat-header-name">{current.fullName}</div>
              <div className="vidya-status-dot">
                {apiKey ? "Online · Ready to teach" : "⚠️ API key needed"}
              </div>
            </div>
            <div className="vidya-exam-ind"
              style={{ background: current.examBg, color: current.color, border: `1px solid ${current.examBorder}` }}>
              {current.exam}
            </div>
          </div>

          {/* Messages */}
          <div className="vidya-chatbox" ref={chatboxRef}>
            <div className="vidya-welcome-card" style={{ borderColor: `rgba(${current.colorRGB},0.18)`, background: `linear-gradient(135deg,rgba(${current.colorRGB},0.07),rgba(0,0,0,0.2))` }}>
              <h3>🎯 Preparing for {current.exam}</h3>
              <p>Ask me anything — concepts, solved examples, shortcuts, or exam strategy. You can also <strong>📷 send a photo</strong> of any question, diagram, or textbook page!</p>
              <div className="vidya-w-tags">
                {current.subjects.map(s => <span key={s} className="vidya-w-tag">📚 {s}</span>)}
                <span className="vidya-w-tag">📖 NCERT Based</span>
                <span className="vidya-w-tag">✅ Exam Focused</span>
                <span className="vidya-w-tag">📷 Image Support</span>
              </div>
            </div>

            {messages.map(msg => (
              <div key={msg.id}
                className={`vidya-msg ${msg.role === "user" ? "user" : "bot"}`}
                style={msg.role === "user" ? { background: `linear-gradient(135deg,${current.color},${current.color}cc)` } : {}}>
                {/* Show image preview inside user message bubble */}
                {msg.imagePreview && (
                  <img
                    src={msg.imagePreview}
                    alt="uploaded question"
                    style={{
                      display: "block",
                      maxWidth: "220px",
                      maxHeight: "180px",
                      borderRadius: "8px",
                      marginBottom: msg.text && msg.text !== "📷 (image sent)" ? "8px" : "0",
                      objectFit: "contain",
                      background: "rgba(255,255,255,0.1)",
                    }}
                  />
                )}
                {msg.text && msg.text !== "📷 (image sent)" && msg.text}
              </div>
            ))}

            {busy && (
              <div className="vidya-msg bot vidya-typing">
                <span /><span /><span />
              </div>
            )}
          </div>

          {/* ── Image preview above input ── */}
          {uploadedImage && (
            <div style={{
              display: "flex",
              alignItems: "center",
              gap: "10px",
              padding: "8px 14px",
              background: "rgba(255,255,255,0.05)",
              borderTop: "1px solid rgba(255,255,255,0.08)",
            }}>
              <img
                src={uploadedImage.previewUrl}
                alt="preview"
                style={{
                  width: "56px",
                  height: "56px",
                  objectFit: "cover",
                  borderRadius: "8px",
                  border: `2px solid ${current.color}`,
                }}
              />
              <div style={{ flex: 1, fontSize: "12px", color: "rgba(255,255,255,0.6)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                📷 {uploadedImage.name}
              </div>
              <button
                onClick={removeImage}
                title="Remove image"
                style={{
                  background: "rgba(255,255,255,0.1)",
                  border: "none",
                  borderRadius: "50%",
                  width: "26px",
                  height: "26px",
                  cursor: "pointer",
                  color: "white",
                  fontSize: "14px",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  flexShrink: 0,
                }}>
                ✕
              </button>
            </div>
          )}

          {/* Input area */}
          <div className="vidya-input-area">

            {/* Hidden file input */}
            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              style={{ display: "none" }}
              onChange={handleImageSelect}
            />

            {/* Camera / Upload button */}
            <button
              className="vidya-img-upload-btn"
              title="Send a photo of your question or diagram"
              onClick={() => fileInputRef.current?.click()}
              disabled={!apiKey}
              style={{
                background: uploadedImage ? `linear-gradient(135deg,${current.color},${current.color}bb)` : "rgba(255,255,255,0.08)",
                border: `1.5px solid ${uploadedImage ? current.color : "rgba(255,255,255,0.15)"}`,
                borderRadius: "10px",
                padding: "0 12px",
                height: "44px",
                cursor: apiKey ? "pointer" : "not-allowed",
                fontSize: "18px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                flexShrink: 0,
                transition: "all 0.2s",
              }}>
              📷
            </button>

            <input
              ref={inputRef}
              className="vidya-input"
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => { if (e.key === "Enter") { e.preventDefault(); sendMessage(); } }}
              placeholder={
                uploadedImage
                  ? "Add a question about this image (optional)…"
                  : apiKey
                  ? "Ask your NEET / JEE doubt here… or 📷 send a photo"
                  : "Enter API key to start chatting…"
              }
              style={{ "--focus-color": current.color }}
              disabled={!apiKey}
            />
            <button
              className="vidya-send-btn"
              style={{ background: `linear-gradient(135deg,${current.color},${current.color}bb)` }}
              onClick={() => sendMessage()}
              disabled={busy || !apiKey || (!input.trim() && !uploadedImage)}>
              <svg viewBox="0 0 24 24" width="17" height="17" fill="#000">
                <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z" />
              </svg>
            </button>
          </div>
        </main>
      </div>
    </PageLayout>
  );
}
